      }
      .th-term{
        background:#D6EAF8;color:#1A5276;
        font-weight:600;font-size:${fs(13)}px;
        font-family:'DM Serif Display',serif;
        font-style:italic;letter-spacing:0.3px;
      }
      .th-overall{
        background:#D6EAF8;color:#1A5276;
        font-weight:600;font-size:${fs(11)}px;
        font-family:'DM Sans',sans-serif;
      }
      .th-sub{
        background:#EBF5FB;color:#2471A3;
        font-weight:600;font-size:${fs(9.5)}px;
        font-family:'DM Sans',sans-serif;
      }
      .th-max{
        background:#FDEDEC;color:#C0392B;
        font-weight:700;font-size:${fs(10.5)}px;
        font-family:'DM Sans',sans-serif;
        border-top:1px solid #F5B7B1;
      }
      .td-subj{
        text-align:center;font-weight:600;
        color:#1A5276;background:#EBF5FB;
        font-size:${fs(12)}px;
        font-family:'DM Sans',sans-serif;
      }
      .td-tot{
        background:#D6EAF8;font-weight:700;color:#1A5276;
        font-family:'DM Sans',sans-serif;
      }
      .td-grand{
        background:#EAFAF1;font-weight:700;
        color:#1E8449;font-size:${fs(13)}px;
        font-family:'DM Serif Display',serif;
      }
      .td-grade{font-weight:600;font-size:${fs(12)}px;color:#1A5276;font-family:'DM Sans',sans-serif}
      .td-rank{font-weight:500;color:#7F8C8D;font-family:'DM Sans',sans-serif}
      tbody tr:nth-child(even) td:not(.td-subj):not(.td-tot):not(.td-grand){background:#F4FAFF}

      /* ── GRADING NOTE ── */
      .gn{
        font-family:'DM Sans',sans-serif;
        font-size:${fs(9)}px;
        padding:${pd(5)}px ${pd(10)}px;
        border-left:3px solid #5DADE2;
        margin:${pd(5)}px ${pd(4)}px;
        color:#5D6D7E;line-height:1.6;
        background:#F4FAFF;
      }

      /* ── TOTALS ROW ── */
      .tb{
        display:flex;align-items:center;justify-content:space-between;
        padding:${pd(8)}px ${pd(18)}px;
        background:#EBF5FB;
        border-top:1px solid #AED6F1;
